import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import Navbar from "./components/Navbar";
import ProtectedRoute from "./components/ProtectedRoute";

// Pages
import Login from "./pages/Login";
import Register from "./pages/Register";
import Home from "./pages/Home";
import EventDetails from "./pages/EventDetails";
import MyBookings from "./pages/MyBookings";
import Payment from "./pages/Payments";

// Admin Pages
import AdminDashboard from "./pages/Admin/AdminDashboard";
import AllBooking from "./pages/Admin/AllBooking";
import CreateEvent from "./pages/Admin/CreateEvent";
import ManageEvents from "./pages/Admin/ManageEvents";

// Single CSS import
import "./styles/App.css";

function App() {
  const user = JSON.parse(localStorage.getItem("user"));

  return (
    <Router>
      <Navbar />

      <Routes>
        {/* Public Routes */}
        <Route path="/" element={user ? <Navigate to={user.role === "admin" ? "/admin" : "/home"} /> : <Navigate to="/login" />} />
        <Route path="/login" element={user ? <Navigate to={user.role === "admin" ? "/admin" : "/home"} /> : <Login />} />
        <Route path="/register" element={user ? <Navigate to={user.role === "admin" ? "/admin" : "/home"} /> : <Register />} />

        {/* User Protected Routes */}
        <Route element={<ProtectedRoute allowedRoles={["user"]} />}>
          <Route path="/home" element={<Home />} />
          <Route path="/events/:id" element={<EventDetails />} />
          <Route path="/my-bookings" element={<MyBookings />} />
          <Route path="/payments" element={<Payments />} />
        </Route>

        {/* Admin Protected Routes */}
        <Route element={<ProtectedRoute allowedRoles={["admin"]} />}>
          <Route path="/admin" element={<AdminDashboard />} />
          <Route path="/admin/bookings" element={<AllBookings />} />
          <Route path="/admin/create-event" element={<CreateEvent />} />
          <Route path="/admin/manage-events" element={<ManageEvents />} />
        </Route>

        {/* Catch-all */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default App;
